import subprocess

def convertDocument(inputFile, outputFile, outputFormat):
    """
    This function converts documents between formats using LibreOffice headless mode.

    Args:
        inputFile (str): The path to the input file.
        outputFile (str): The path to save the converted file.
        outputFormat (str): The format of the output file.

    Returns:
        None
    """
    command = [
        'soffice',
        '--headless',
        '--convert-to',
        outputFormat,
        inputFile,
        '--outdir',
        './'
    ]
    
    try:
        subprocess.run(command, check=True)
        print(f"Conversion successful. Output file saved as {outputFile}")
    except subprocess.CalledProcessError as e:
        print("An error occurred during conversion.")
        print(e)

